INSERT INTO `videos` VALUES (52,5405885462,'22192f63a7b3aed2d903c9bff12e962a','video_1769765538_5405885462_22192f63a7b3aed2d903c9bff12e962a.mp4','Страх — это иллюзия','video','Страх — главный враг прогресса. Этот метод доказывает, что бояться нечего — результат приятно удивит. #лайфхак #психология #masterhacks','#лайфхак #психология #masterhacks',6,'approved',0,0,'2026-01-30 12:32:18','2026-01-30 12:40:08',0,NULL,0,0),(53,5405885462,'79aed1f4fdf9fe3b4a29354c711b960b','video_1770113759_5405885462_79aed1f4fdf9fe3b4a29354c711b960b.mp4','Метод из народа','video','Проверенный поколениями способ, который работает лучше дорогих гаджетов. Народная мудрость рулит. #народныйметод #советы #лайфхак #masterhacks','#народныйметод #советы #лайфхак #masterhacks',12,'approved',0,0,'2026-02-03 13:15:59','2026-02-03 13:16:24',0,NULL,0,0),(54,5405885462,'b4bf76844ae7c8b7a17bafdc61f7ba52','video_1770114131_5405885462_b4bf76844ae7c8b7a17bafdc61f7ba52.mp4','Ключ к пониманию','video','Все ищут сложные пути, а разгадка лежит на поверхности. Этот секрет меняет правила игры. #секрет #лайфхак #masterhacks','#секрет #лайфхак #masterhacks',14,'approved',0,0,'2026-02-03 13:22:11','2026-02-03 13:22:29',0,NULL,0,0),(55,5405885462,'7dc9bb11ee44a08a1546a0cb72564915','video_1770114465_5405885462_7dc9bb11ee44a08a1546a0cb72564915.mp4','Незаслуженно забыто','video','Старые технологии, о которых незаслуженно забыли. А зря — они решают проблему быстрее и дешевле. #классика #технологии #лайфхак #masterhacks','#классика #технологии #лайфхак #masterhacks',8,'approved',0,0,'2026-02-03 13:27:45','2026-02-03 13:28:04',0,NULL,0,0),(56,5405885462,'0f745dfc5849ef23058bc3a5d8775abb','video_1770114690_5405885462_0f745dfc5849ef23058bc3a5d8775abb.mp4','Работает как часы','video','Безотказный метод, проверенный сотнями людей. Работает даже если руки из жопы. #надёжность #советы #masterhacks','#надёжность #советы #masterhacks',12,'approved',0,0,'2026-02-03 13:31:30','2026-02-03 13:31:46',0,NULL,0,0),(57,5405885462,'d3dfe